uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;



    vec2 d = uTexSize.zw*12;
    vec3 dx = ( GetBlur1(vUv + vec2(1,0)*d) - GetBlur1(vUv-vec2(1,0)*d) );
    vec3 dy = ( GetBlur1(vUv + vec2(0,1)*d) - GetBlur1(vUv-vec2(0,1)*d) );
    vec2 my_uv = vUv + vec2(dx.y,dy.y)*0.1;

vec3 re;

//vUv = vUv + 0.02*vec2(cos(vUv.y*27),sin(vUv.x*39));
vec2 m = vec2(1-q4,q8);
vec2 bg_uv = m + (vUv-m)*0.992; // subtle 3D shadow drop
vec2 mid_uv = m + (vUv-m)*0.996;
ret = mix( vec3(0,0,0.2), vec3(0.3,0,1),texture( sampler_fw_main, bg_uv).y);
ret = mix(ret, vec3(1,1,0), max(GetBlur1(bg_uv).z*1.5,texture( sampler_main, mid_uv).z)); // if that isn't a cool glow effect?
ret *= 1-GetBlur1(bg_uv).x*2; // drop shadow
ret = mix( ret, vec3(1,0.1,0.4),texture( sampler_fw_main, vUv).x);

re = texture( sampler_rand00, my_uv);
ret = mix( texture(sampler_rand01,my_uv), re, ret.x);


  fragColor = ret;
}
